class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        n = len(binary)
        binary = list(binary)
        i = 0
        for j in range(n):
            if binary[j] == '0':
                if i < j:
                    binary[i] = '1'
                    i += 1
                i += 1
        i -= 1
        while i < n:
            binary[i] = '1'
            i += 1
        return ''.join(binary)
